// Error Trigger payload shape:
// $json.execution.error.message, .error.cause.status, .error.name, .error.stack
// $json.execution.lastNodeExecuted, .execution.id, .execution.url
// $json.workflow.name, .workflow.id

const input = $input.first().json;
const execution = input.execution || {};
const workflow = input.workflow || {};
const error = execution.error || {};
const cause = error.cause || {};

const errorMessage = (error.message || '').toLowerCase();
const statusCode = cause.status || cause.statusCode || 0;
const lastNode = execution.lastNodeExecuted || 'unknown';
const workflowName = workflow.name || 'unknown';
const executionId = execution.id || $execution.id;

// Infer API domain from workflow name convention
const wfLower = workflowName.toLowerCase();
let api = 'unknown';
if (wfLower.includes('crm')) api = 'crm';
else if (wfLower.includes('ads')) api = 'ads';
else if (wfLower.includes('analytics')) api = 'analytics';
else if (wfLower.includes('google suite') || wfLower.includes('google')) api = 'google';
else if (wfLower.includes('handover')) api = 'platform';
else if (wfLower.includes('github')) api = 'github';
else if (wfLower.includes('browser')) api = 'browser';
else if (wfLower.includes('agent')) api = 'agent';
else if (wfLower.includes('mac bridge') || wfLower.includes('colab')) api = 'compute';
else if (wfLower.includes('mcp')) api = 'gateway';

let category = 'unknown';
let severity = 'warning';
let suggested_action = 'escalate';

if (statusCode === 401 || statusCode === 403 ||
    errorMessage.includes('unauthorized') || errorMessage.includes('forbidden') ||
    errorMessage.includes('authentication') || errorMessage.includes('invalid token') ||
    errorMessage.includes('credential')) {
  category = 'auth_error';
  severity = 'critical';
  suggested_action = 'escalate';
} else if (statusCode === 429 ||
    errorMessage.includes('rate limit') || errorMessage.includes('too many requests') ||
    errorMessage.includes('quota exceeded')) {
  category = 'rate_limit';
  severity = 'warning';
  suggested_action = 'retry';
} else if (errorMessage.includes('timeout') || errorMessage.includes('timed out') ||
    errorMessage.includes('econnaborted') || errorMessage.includes('econnreset') ||
    errorMessage.includes('socket hang up')) {
  category = 'timeout';
  severity = 'warning';
  suggested_action = 'retry';
} else if (statusCode >= 500) {
  category = 'api_error';
  severity = 'critical';
  suggested_action = 'retry';
} else if (statusCode === 400 || statusCode === 422 ||
    errorMessage.includes('validation') || errorMessage.includes('invalid')) {
  category = 'validation_error';
  severity = 'info';
  suggested_action = 'ignore';
} else if (statusCode >= 400 && statusCode < 500) {
  category = 'api_error';
  severity = 'warning';
  suggested_action = 'escalate';
} else if (errorMessage.includes('cannot read') || errorMessage.includes('is not a function') ||
    errorMessage.includes('undefined') || errorMessage.includes('null')) {
  category = 'code_error';
  severity = 'critical';
  suggested_action = 'escalate';
} else if (errorMessage) {
  category = 'api_error';
  severity = 'warning';
  suggested_action = 'escalate';
}

return [{
  json: {
    error_id: executionId,
    category,
    severity,
    suggested_action,
    original_error: {
      message: error.message || 'No error message provided',
      description: error.description || '',
      status_code: statusCode,
      error_type: error.name || 'NodeOperationError',
      source_workflow: workflowName,
      source_workflow_id: workflow.id || 'unknown',
      source_node: lastNode,
      api,
      client: 'unknown',
      execution_url: execution.url || '',
      stack: (error.stack || '').substring(0, 500)
    },
    classified_at: new Date().toISOString()
  }
}];

const error = $input.first().json;

const logEntry = {
  log_type: 'error',
  error_id: error.error_id,
  category: error.category,
  severity: error.severity,
  suggested_action: error.suggested_action,
  source_workflow: error.original_error.source_workflow,
  source_workflow_id: error.original_error.source_workflow_id,
  source_node: error.original_error.source_node,
  api: error.original_error.api,
  client: error.original_error.client,
  error_message: error.original_error.message,
  status_code: error.original_error.status_code,
  execution_url: error.original_error.execution_url,
  classified_at: error.classified_at,
  logged_at: new Date().toISOString(),
  metadata: {
    handler_workflow_id: $workflow.id,
    handler_execution_id: $execution.id
  }
};

console.log(JSON.stringify(logEntry));

return [{ json: { ...error, log_entry: logEntry, logged: true } }];

const error = $input.first().json;

return [{
  json: {
    error_id: error.error_id,
    category: error.category,
    severity: error.severity,
    suggested_action: error.suggested_action,
    source_workflow: error.original_error.source_workflow,
    alerted: error.severity === 'critical',
    logged: true,
    processed_at: new Date().toISOString()
  }
}];
